    private string nombre = "";
    private string email = "";
    private string password = "";
    private string mensaje = "";

    private async Task Registrar()
    {
        mensaje = "Creando usuario en Firebase...";

        var resultado = await authService.Register(email, password);

        if (resultado.Contains("localId"))
        {
            string firebaseUid = ExtraerUid(resultado);

            postgresService.InsertarUsuario(
                firebaseUid,
                nombre,
                email
            );

            mensaje = "Usuario registrado correctamente.";
        }
        else
        {
            mensaje = "Error al registrar usuario.";
        }
    }

    private string ExtraerUid(string json)
    {
        using var doc = System.Text.Json.JsonDocument.Parse(json);

        return doc.RootElement
                  .GetProperty("localId")
                  .GetString()!;
    }

